mapper.update:
UPDATE user_learning_profiles SET current_level_code = CASE WHEN current_level_code IS NULL THEN #{currentLevelCode}
WHEN current_level_code = 'GOLD' THEN 'GOLD'
WHEN current_level_code = 'SILVER' AND #{currentLevelCode} = 'GOLD' THEN 'GOLD'
WHEN current_level_code = 'SILVER' THEN 'SILVER'
WHEN current_level_code = 'BRONZE' AND #{currentLevelCode} IN ('SILVER', 'GOLD') THEN #{currentLevelCode}
ELSE current_level_code END, updated_at = NOW() WHERE user_id = #{userId}
